<?php
namespace App\Http\Controllers;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Equipment\CharacterEquipmentSummaryService;use App\Domain\Equipment\Exceptions\InsufficientEquipmentInventoryCapacityException;use App\Domain\Inventory\CharacterInventorySummaryService;use App\Http\Requests\Equipment\EquipCharacterItemRequest;use App\Http\Requests\Equipment\UnequipCharacterItemRequest;use App\Models\Character;use Illuminate\Database\Eloquent\ModelNotFoundException;use InvalidArgumentException;use RuntimeException;
final class CharacterEquipmentController extends Controller{public function equip(EquipCharacterItemRequest $request,Character $character,CharacterEquipmentService $service,CharacterEquipmentSummaryService $equipment,CharacterInventorySummaryService $inventory){$this->authorize('view',$character);try{$result=$service->equip($character,$request->validated()['item_instance_uuid'],$request->validated()['slot']);return$this->respond($request,$character,$result,$equipment,$inventory,$result->modified()?'Objeto equipado correctamente.':'El objeto ya estaba equipado en ese slot.','characters.inventory.index');}catch(ModelNotFoundException $e){return$this->error($request,$character,'No se pudo equipar el objeto solicitado.','characters.inventory.index',404);}catch(InvalidArgumentException $e){return$this->error($request,$character,$e->getMessage(),'characters.inventory.index',422);}catch(RuntimeException $e){return$this->error($request,$character,'El estado del equipamiento es inconsistente.','characters.inventory.index',409);}}public function unequip(UnequipCharacterItemRequest $request,Character $character,CharacterEquipmentService $service,CharacterEquipmentSummaryService $equipment,CharacterInventorySummaryService $inventory){$this->authorize('view',$character);try{$result=$service->unequip($character,$request->validated()['slot']);return$this->respond($request,$character,$result,$equipment,$inventory,$result->modified()?'Objeto desequipado correctamente.':'El slot ya estaba vacío.','characters.show');}catch(InsufficientEquipmentInventoryCapacityException $e){return$this->error($request,$character,$e->getMessage(),'characters.show',422);}catch(RuntimeException $e){return$this->error($request,$character,'El estado del equipamiento es inconsistente.','characters.show',409);}}private function respond($request,$character,$result,$equipment,$inventory,$message,$route){if($request->expectsJson())return response()->json(['message'=>$message,'mutation'=>$result->toArray(),'equipment'=>$equipment->snapshot($character)->toArray(),'inventory'=>$inventory->snapshot($character)]);return redirect()->route($route,$character)->with('status',$message);}private function error($request,$character,$message,$route,$status){if($request->expectsJson())return response()->json(['message'=>$message],$status);return redirect()->route($route,$character)->withErrors(['equipment'=>$message]);}}
